import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            long[][] rows = new long[N][N];
            for (int i = 0; i < N; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                for (int j = 0; j < N; j++) {
                    rows[i][j] = Long.parseLong(st.nextToken());
                }
                Arrays.sort(rows[i]);
            }
            long[] dpPrev = new long[N];
            for (int j = 0; j < N; j++) dpPrev[j] = rows[0][j];
            for (int i = 1; i < N; i++) {
                long[] prefixMax = new long[N];
                prefixMax[0] = dpPrev[0];
                for (int j = 1; j < N; j++) prefixMax[j] = Math.max(prefixMax[j - 1], dpPrev[j]);
                long[] dpCurr = new long[N];
                Arrays.fill(dpCurr, -1L);
                for (int j = 0; j < N; j++) {
                    long val = rows[i][j];
                    int idx = upperBound(rows[i - 1], val - 1); // last index with < val
                    if (idx >= 0) {
                        dpCurr[j] = prefixMax[idx] + val;
                    }
                }
                dpPrev = dpCurr;
            }
            long ans = -1L;
            for (long v : dpPrev) if (v > ans) ans = v;
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }

    // returns last index where arr[idx] <= target, or -1 if none
    private static int upperBound(long[] arr, long target) {
        int lo = 0, hi = arr.length - 1, res = -1;
        while (lo <= hi) {
            int mid = (lo + hi) >>> 1;
            if (arr[mid] <= target) {
                res = mid;
                lo = mid + 1;
            } else {
                hi = mid - 1;
            }
        }
        return res;
    }
}

